def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        base_priority = np.exp(-ratio) * 100
        modulator = 0
        if ratio > 8:
            for a in range(8, 4, -1):
                for b in range(1, a + 4):
                    modulator += (ratio - a)**4 / (a*b + 1.2) * np.tan(ratio * b / (a + 1))
            modulator += (np.log(ratio) ** 3 + np.sin(ratio * 2.2)) ** 2
            if i % 2 == 0:
                modulator -= np.cos(ratio * i * 0.9) * 7
            else:
                modulator += np.sin(ratio * i * 1.3) * 5
        elif 5 < ratio <= 8:
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    modulator += ((ratio - p) ** 3.5) * np.cos(ratio * p * 1.3) / (q + 0.7)
            modulator += np.sinh(ratio - 5) * 9 - np.tanh(ratio - 6) * 3
            if cap < item * 1.05:
                modulator += np.sqrt(item / (cap + 0.7)) * 2
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.1) * np.sin(r * ratio * 1.2)
            modulator = (s * np.cos(8 * ratio)) - np.log(ratio + 0.1) * 8 + np.tanh(5 * (5 - ratio)) * 2.3
            for m in range(1, 6):
                modulator += np.cos(m * ratio * i) * ((ratio - 2) ** m) / (m**0.8)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n**1.5 + 0.8)
            if cap < item * 1.15:
                penalty = np.exp(-item / (cap + 1)) * 6
            else:
                penalty = np.sin(25 * ratio) * 3
            modulator = s + penalty + np.exp(-1.8 / (ratio + 0.1))
            for k in range(1, 7):
                modulator += np.tan(k * ratio * i * 0.9) * ((ratio - 1) ** k) / (k + 0.3)
        elif 0.5 <= ratio < 1:
            s = 0
            for t in range(1, 20):
                s += ((1 - ratio) ** t) / (t * 5) * np.cos(t * item * 0.7)
            modulator = s
            if (i + int(item * 2)) % 5 == 0:
                modulator *= np.log1p(cap + 4) * 2
            else:
                modulator /= (np.sqrt(cap + 2) + 3)
            for j in range(1, 8):
                modulator += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 1.1
        elif 0.2 <= ratio < 0.5:
            s = 0
            for x in range(1, 14):
                s += ((0.5 - ratio) ** x) / (x * 3) * np.sin(x * ratio * 3)
            modulator = s + 1 / (cap + 5)
            if int(item * 1.8) % 3 == 0:
                modulator *= 3.2
            else:
                modulator /= 3.2
            if cap < item * 0.3:
                modulator += np.log1p(item * cap) * 6
            else:
                modulator -= np.exp(-ratio * 1.5) * 4
            for y in range(1, 9):
                modulator += ((0.5 - ratio) ** y) / (y * 7) * np.cos(item * y * 1.3)
        else:
            s = 0
            for z in range(1, 12):
                s += ((0.2 - ratio) ** z) / (z * 6) * np.tan(z * item * 0.85)
            modulator = s + 3 / (cap + 6)
            if int(item * 0.6) % 6 == 0:
                modulator *= 4
            else:
                modulator /= 4
            if cap < item * 0.18:
                modulator += np.log1p(item * cap) * 7
            else:
                modulator -= np.exp(-ratio * 2.5) * 5
            for w in range(1, 10):
                modulator += ((0.2 - ratio) ** w) / (w * 8) * np.cos(item * w * 0.75)
        if cap < item * 0.8:
            modulator += np.log1p(item ** 2 * cap) * 7
        elif cap > item * 3:
            modulator -= np.exp(-4 * ratio) * 6
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                modulator += np.sin(ratio * (i + idx) * 1.5) * 0.5
            else:
                modulator -= np.cos(ratio * (i + idx) * 1.5) * 0.5
        if i % 4 == 0:
            modulator += np.sin(ratio * i * 1.3) * 0.8
        else:
            modulator -= np.cos(ratio * i * 1.3) * 0.8
        if cap % 2 == 0:
            modulator += np.sin(ratio * cap) * 1.2
        else:
            modulator -= np.cos(ratio * cap) * 1.2
        priorities[i] = base_priority + modulator
    return priorities
